// Some portions generated by Co-Pilot
import { describe, it, expect, vi, afterEach } from "vitest";
import { render, cleanup } from "@testing-library/react";
import DocTableOfContents from "../index";

describe("DocTableOfContents", () => {
  afterEach(() => {
    cleanup();
    document.body.innerHTML = "";
  });

  it("renders nothing when no headings with ids exist", () => {
    const article = document.createElement("div");
    article.setAttribute("role", "article");
    article.innerHTML = "<p>Just text</p>";
    document.body.appendChild(article);

    const { container } = render(<DocTableOfContents />);
    expect(container.querySelector("nav")).toBeNull();
  });

  it("renders headings from the article element", () => {
    const article = document.createElement("div");
    article.setAttribute("role", "article");
    article.innerHTML = `
      <h2 id="section-1">Section One</h2>
      <h3 id="section-1a">Sub Section</h3>
      <h2 id="section-2">Section Two</h2>
    `;
    document.body.appendChild(article);

    const { container } = render(<DocTableOfContents />);

    expect(container.textContent).toContain("On this page");
    const links = container.querySelectorAll("a");
    const linkTexts = Array.from(links).map((a) => a.textContent);
    expect(linkTexts).toContain("Section One");
    expect(linkTexts).toContain("Sub Section");
    expect(linkTexts).toContain("Section Two");
  });

  it("creates links with correct href for each heading", () => {
    const article = document.createElement("div");
    article.setAttribute("role", "article");
    article.innerHTML = `<h2 id="my-heading">My Heading</h2>`;
    document.body.appendChild(article);

    const { container } = render(<DocTableOfContents />);

    const link = container.querySelector('a[href="#my-heading"]');
    expect(link).toBeInTheDocument();
    expect(link?.textContent).toBe("My Heading");
  });

  it("indents h3 headings more than h2", () => {
    const article = document.createElement("div");
    article.setAttribute("role", "article");
    article.innerHTML = `
      <h2 id="h2-item">H2 Item</h2>
      <h3 id="h3-item">H3 Item</h3>
    `;
    document.body.appendChild(article);

    const { container } = render(<DocTableOfContents />);

    const h2Link = container.querySelector('a[href="#h2-item"]');
    const h3Link = container.querySelector('a[href="#h3-item"]');
    expect(h2Link).toHaveClass("pl-3");
    expect(h3Link).toHaveClass("pl-5");
  });

  it("has accessible navigation landmark", () => {
    const article = document.createElement("div");
    article.setAttribute("role", "article");
    article.innerHTML = `<h2 id="heading">Heading</h2>`;
    document.body.appendChild(article);

    const { container } = render(<DocTableOfContents />);

    const nav = container.querySelector("nav");
    expect(nav).toHaveAttribute("aria-label", "On this page");
  });

  it("ignores headings without id", () => {
    const article = document.createElement("div");
    article.setAttribute("role", "article");
    article.innerHTML = `
      <h2>No ID Heading</h2>
      <h2 id="has-id">Has ID</h2>
    `;
    document.body.appendChild(article);

    const { container } = render(<DocTableOfContents />);

    const links = container.querySelectorAll("a");
    const linkTexts = Array.from(links).map((a) => a.textContent);
    expect(linkTexts).not.toContain("No ID Heading");
    expect(linkTexts).toContain("Has ID");
  });
});
